input.new_string:
const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;

type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
};

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

const sumBasePremiums = (items: Item[]): number =>
  items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);

const quotePremium = (step: QuoteStep): number => {
  const base = sumBasePremiums(step.items);
  return Math.ceil(base * (1 + FIRST_INSURANCE_SURCHARGE_RATE)) + PROCESSING_FEE;
};

